            Tags = """["payables","ap","accounting","walkthrough"]""",
            ContentJson = """{"appRoute":"/payables","startButtonLabel":"Tour Payables","steps":[{"element":".tab-bar","popover":{"title":"Payables Tabs","description":"The Payables page is split into tabs: Bills (vendor invoices you owe), Payments (money sent to vendors), Batches (payment batches), and Accounts (vendor bank accounts). The Bills and Payments tabs are the day-to-day AP workspace.","side":"bottom"}},{"element":"[data-testid='new-vendor-bill-btn']","popover":{"title":"New Bill Button","description":"On the Bills tab, click here to enter a vendor bill. You pick a vendor, set the bill and due dates, and add line items — either as free-form standalone lines or matched From Purchase Order. New bills start in Draft status with no general-ledger impact.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Vendor and Status Filters","description":"Filter the table by vendor (All Vendors by default) and by status. The Bills status filter offers Draft, Approved, Partially Paid, Paid, and Void. The Payments tab filters by payment method and transmission status instead.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bills Table","description":"Each row is a vendor bill: Bill Number, Vendor, Vendor Invoice #, a color-coded Status chip, Bill Date, Due Date, Total, Paid, and Balance Due. Balance Due is highlighted when it is greater than zero. Click any row to open the bill detail panel.","side":"top"}},{"element":".tab-bar","popover":{"title":"New Payment Button","description":"Switch to the Payments tab, then use its New Payment button to record a vendor payment. After choosing the vendor, the dialog loads that vendor's payable bills (Approved or Partially Paid) so you can apply the payment across them. The dialog uses data-testids like vendor-payment-method, vendor-payment-amount, and vendor-payment-app-amount.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bill Detail Panel","description":"Clicking a bill row opens its detail panel: status chip, vendor link, linked Purchase Order, line items, and the totals block (Subtotal, Tax, Total, Paid, Balance Due). Action buttons appear by status — Approve Bill (data-testid approve-bill-btn) from Draft, and Void Bill (data-testid void-bill-btn) from Draft or Approved when nothing has been paid.","side":"top"}},{"element":"app-data-table","popover":{"title":"Payment Detail Panel","description":"On the Payments tab, clicking a payment row opens its detail: vendor, method, amount, applied and unapplied amounts, and the bill applications table. For electronic payments a Bank Transmission section shows status and attempts, with Retry Transmission for failures, Attest Wire for queued wires, and Void Payment to reverse a payment.","side":"top"}}]}"""
